let articuloCompleto = '';
try {
  articuloCompleto = $input.first().json.data || $input.first().json || '';
} catch(e) {
  articuloCompleto = 'No se pudo acceder a la noticia completa. Basate únicamente en el titular y el resumen proporcionado.';
}

const temaActual = $('Loop Temas Pendientes').item.json;
const textoLimpio = typeof articuloCompleto === 'string' ? articuloCompleto.substring(0, 15000) : 'Sin información adicional.';

return [{
  json: {
    ...temaActual,
    investigacion_profunda: textoLimpio
  }
}];

const items = $input.all().slice(0, 10);
let newsText = 'ÚLTIMAS NOTICIAS REALES DE HOY EN COLOMBIA:\n\n';

items.forEach((item, i) => {
  const titulo = item.json.title || 'Sin título';
  const url = item.json.link || '';
  let resumen = item.json.contentSnippet || item.json.content || item.json.description || '';
  resumen = resumen.replace(/<[^>]*>?/gm, '').trim();

  newsText += `--- NOTICIA ${i+1} ---\n`;
  newsText += `TÍTULO: ${titulo}\n`;
  newsText += `URL: ${url}\n`;
  newsText += `RESUMEN: ${resumen}\n\n`;
});

return [{ json: { contextNoticias: newsText } }];

const source = $input.first().json;
let rawText = '';
if (typeof source?.choices?.[0]?.message?.content === 'string') {
  rawText = source.choices[0].message.content;
} else if (Array.isArray(source?.choices?.[0]?.message?.content)) {
  rawText = source.choices[0].message.content.map(p => p?.text || '').join('');
} else {
  rawText = JSON.stringify(source);
}
rawText = rawText.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
let topics;
try { topics = JSON.parse(rawText); } catch(e) {
  const m = rawText.match(/\[([\s\S]+?)\]/);
  if (!m) throw new Error('No se pudo parsear array de temas: ' + rawText.substring(0, 500));
  try { topics = JSON.parse('[' + m[1] + ']'); } catch(e2) {
    throw new Error('Parse fallido incluso con extracción manual: ' + rawText.substring(0, 500));
  }
}
if (!Array.isArray(topics) || topics.length === 0) throw new Error('El AI no devolvió temas válidos.');
const result = topics.slice(0, 3).map(t => ({ json: { title: (t.title || '').trim(), keywords: (t.keywords || '').trim(), category_slug: (t.category_slug || 'ia').trim(), source_url: (t.source_url || '').trim() } }));
console.log('Temas parseados del AI:', result.map(r => r.json.title));
return result;

const allItems = $input.all();

const aiTopics = allItems.filter(i => i.json.keywords !== undefined);
const supabaseItems = allItems.filter(i => i.json.keywords === undefined);

console.log(`Items del AI: ${aiTopics.length}, Items de Supabase: ${supabaseItems.length}`);

const existingTitles = new Set();
for (const item of supabaseItems) {
  const raw = item.json;
  const arr = Array.isArray(raw) ? raw : (raw?.data || [raw]);
  for (const t of arr) {
    if (t?.title) existingTitles.add(t.title.toLowerCase().trim());
  }
}

console.log(`Títulos existentes en Supabase: ${existingTitles.size}`, [...existingTitles]);

const newTopics = aiTopics.filter(item => {
  const t = (item.json.title || '').toLowerCase().trim();
  const isDup = existingTitles.has(t);
  if (isDup) console.log(`Duplicado detectado, saltando: "${item.json.title}"`);
  return t.length > 5 && !isDup;
});

if (newTopics.length === 0) {
  console.log('Todos los temas propuestos ya existen. No se insertarán duplicados.');
  return [{ json: { skipped: true, message: 'No hay temas nuevos para insertar.' } }];
}

console.log(`Temas nuevos a insertar: ${newTopics.length}`, newTopics.map(t => t.json.title));
return newTopics.map(i => ({ json: i.json }));

// Verificar que el INSERT fue exitoso antes de continuar
const res = $input.first().json;
const inserted = Array.isArray(res) ? res[0] : res;
if (!inserted?.id) {
  console.warn('INSERT no devolvió id, respuesta:', JSON.stringify(res));
} else {
  console.log(`✓ Tema insertado correctamente: id=${inserted.id}, title="${inserted.title}"`);
}
return [{ json: inserted || res }];

const raw = $input.first().json;
console.log('GET Temas Pendientes respuesta raw:', JSON.stringify(raw));

let topics = [];
if (Array.isArray(raw)) {
  topics = raw;
} else if (raw?.data && Array.isArray(raw.data)) {
  topics = raw.data;
} else if (raw?.id) {
  topics = [raw];
}

if (topics.length === 0 || Object.keys(raw).length === 0) {
  console.log('No hay temas pendientes en Supabase. El flujo se detendrá aquí.');
  return []; 
}

return topics.map(t => ({
  json: {
    topic_id: t.id,
    title: t.title,
    keywords: t.keywords || '',
    category_slug: t.category_slug || 'ia',
    source_url: t.source_url || ''
  }
}));

const raw = $input.first()?.json?.content?.parts?.[0]?.text ||
  $input.first()?.json?.choices?.[0]?.message?.content ||
  $input.first()?.json?.text || '';
const text = raw.replace(/\r/g, '').trim();
function cleanPrompt(v) {
  return (v || '').replace(/^["'`]+|["'`]+$/g,'').replace(/\n+/g,' ').replace(/\s+/g,' ').trim();
}
function extractLabeled(label, nextLabels=[]) {
  const next = nextLabels.length ? `(?=\\(${nextLabels.join('|')}\\)|$)` : '$';
  const rx = new RegExp(`\\(${label}\\)\\s*([\\s\\S]+?)${next}`,'i');
  return cleanPrompt(text.match(rx)?.[1] || '');
}
function readWebhookPayload() {
  try {
    const payload = $('Webhook Trigger Manual').first()?.json || {};
    return payload?.body && typeof payload.body === 'object' ? payload.body : payload;
  } catch {
    return {};
  }
}
const webhookPayload = readWebhookPayload();
const requestedProvider = String(webhookPayload.image_provider || 'openrouter').toLowerCase();
const requestedArticleModel = String(webhookPayload.openrouter_model || 'meta-llama/llama-3.3-70b-instruct:free');
const requestedImageModel = String(webhookPayload.openrouter_image_model || 'openai/dall-e-3');
let pA = extractLabeled('A',['B','C']);
let pB = extractLabeled('B',['C']);
let pC = extractLabeled('C',[]);
const bullets = text.split('\n').map(l=>cleanPrompt(l.replace(/^[-*?\d.)\s]+/,''))).filter(Boolean);
if (!pA && bullets[0]) pA = bullets[0];
if (!pB && bullets[1]) pB = bullets[1];
if (!pC && bullets[2]) pC = bullets[2];
if (pA && !pB) pB = `${pA}, editorial lifestyle scene, fashion ecommerce context, different composition`;
if (pA && !pC) pC = `${pA}, secondary supporting visual, alternate angle, AI virtual try-on detail`;
if (!pA) throw new Error('No se pudieron extraer los prompts. Texto: ' + text.substring(0,500));
const topicData = $('Loop Temas Pendientes').item.json;
const sharedMeta = {
  image_provider: requestedProvider,
  openrouter_model: requestedArticleModel,
  openrouter_image_model: requestedImageModel,
};
return [
  { json: { prompt: pA, tipo: 'destacada', orden: 1, ...topicData, ...sharedMeta } },
  { json: { prompt: pB, tipo: 'body1', orden: 2, ...topicData, ...sharedMeta } },
  { json: { prompt: pC, tipo: 'body2', orden: 3, ...topicData, ...sharedMeta } }
];

