const source = $input.item.json;
const promptData = $('Loop Imágenes').item.json;
let imageValue = '';
if (source?.choices?.[0]?.message?.images?.[0]?.image_url?.url) {
  imageValue = source.choices[0].message.images[0].image_url.url;
} else if (source?.choices?.[0]?.message?.images?.[0]?.imageUrl?.url) {
  imageValue = source.choices[0].message.images[0].imageUrl.url;
} else if (source?.choices?.[0]?.message?.content) {
  const content = source.choices[0].message.content;
  const match = content.match(/https:\/\/\S+/);
  imageValue = match ? match[0] : content;
} else if (source?.imageUrl) {
  imageValue = source.imageUrl;
} else if (source?.data?.[0]?.url) {
  imageValue = source.data[0].url;
} else {
  throw new Error('OpenRouter no devolvi? imagen utilizable: ' + JSON.stringify(source).slice(0, 800));
}
return [{ json: { ...promptData, imageUrl: imageValue } }];

const item = $input.item;
const source = item.json.imageUrl || '';
if (!source) {
  throw new Error('OpenRouter no devolvi? imageUrl');
}
const match = source.match(/^data:(image\/[a-zA-Z0-9.+-]+);base64,(.+)$/);
if (!match) {
  throw new Error('OpenRouter devolvi? una imagen no compatible para conversi?n directa');
}
const mimeType = match[1];
const base64 = match[2];
return {
  json: item.json,
  binary: {
    data: {
      data: base64,
      mimeType,
      fileName: `${item.json.tipo || 'imagen'}.png`,
    },
  },
};

const response = $input.item.json;
const currentItem = $('Loop Imágenes').item.json;
const token = '***REMOVED-SECRET***';

async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

async function getPrediction(url) {
  const res = await fetch(url, { headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' } });
  if (!res.ok) throw new Error(`Replicate lookup failed (${res.status}): ${await res.text()}`);
  return await res.json();
}

async function resolvePrediction(pred) {
  let cur = pred;
  for (let i = 0; i < 30; i++) {
    if (cur?.error) throw new Error(`Replicate error en ${currentItem.tipo}: ${cur.error}`);
    if (cur?.status === 'failed' || cur?.status === 'canceled') throw new Error(`Replicate ${cur.status}. ID: ${cur.id}`);
    if (cur?.status === 'succeeded' && cur?.output) {
      const imageUrl = Array.isArray(cur.output) ? cur.output[0] : cur.output;
      await sleep(12000);
      return [{ json: { ...currentItem, imageUrl, predictionId: cur.id } }];
    }
    const pollUrl = cur?.urls?.get;
    if (!pollUrl) throw new Error(`Sin output ni poll URL. Status: ${cur?.status || 'unknown'}`);
    await sleep(4000);
    cur = await getPrediction(pollUrl);
  }
  throw new Error(`Replicate timeout para ${currentItem.tipo}`);
}

return await resolvePrediction(response);

const item = $input.item;
const tipo = item.json.tipo || 'imagen';
if (item.binary?.data) {
  item.binary.data.fileName = `${tipo}.png`;
  item.binary.data.mimeType = 'image/png';
}
return { json: { ...item.json, tipo }, binary: item.binary };

const items = $input.all().sort((a,b) => (a.json.orden||0)-(b.json.orden||0));
console.log('Consolidar recibió', items.length, 'items del Done branch');
if (items.length < 3) throw new Error(`Se esperaban 3 imágenes subidas, se recibieron ${items.length}.`);
const mapImg = i => ({
  id:  i?.json?.path || i?.json?.url || null,
  url: i?.json?.url || null
});
return [{ json: {
  imagen_destacada: mapImg(items[0]),
  imagen_body1:     mapImg(items[1]),
  imagen_body2:     mapImg(items[2])
} }];

const rawItems = $input.all();
const source = rawItems.length === 1 && Array.isArray(rawItems[0].json?.data) ? rawItems[0].json.data : rawItems.map(i => i.json);
const enlacesBlogs = source.slice(0, 8).map(post => ({ titulo: post.title, url: `https://lookitry.com/blog/${post.slug}` }));
return [{ json: { enlacesBlogs } }];

const enlaces = Array.isArray($input.first().json.enlacesBlogs) ? $input.first().json.enlacesBlogs : [];

let imagenes = {};
try {
  imagenes = $('Consolidar URLs Im?genes').first().json || {};
} catch (error) {
  console.log('Advertencia: No se encontraron datos de im?genes en este ciclo.');
}

let tema = {};
try {
  tema = $('Loop Temas Pendientes').item.json || {};
} catch (error) {
  tema = $('Loop Temas Pendientes').first().json || {};
}

return [{
  json: {
    ...tema,
    enlacesBlogs: enlaces,
    imagen_destacada_url: imagenes.imagen_destacada?.url || '',
    imagen_body1_url: imagenes.imagen_body1?.url || '',
    imagen_body2_url: imagenes.imagen_body2?.url || '',
    imagen_destacada_id: imagenes.imagen_destacada?.id || null,
    imagen_body1_id: imagenes.imagen_body1?.id || null,
    imagen_body2_id: imagenes.imagen_body2?.id || null,
  },
}];

const source = $input.item.json;
let rawText = '';
if (typeof source?.choices?.[0]?.message?.content === 'string') {
  rawText = source.choices[0].message.content;
} else if (Array.isArray(source?.choices?.[0]?.message?.content)) {
  rawText = source.choices[0].message.content.map(p => typeof p === 'string' ? p : p?.text || '').join('');
} else if (source?.content?.parts?.[0]?.text) {
  rawText = source.content.parts[0].text;
} else {
  rawText = JSON.stringify(source);
}
rawText = rawText.replace(/```json\s*/gi,'').replace(/```\s*/g,'').trim();
let parsed = null;
try { parsed = JSON.parse(rawText); } catch(_) {}
if (!parsed) {
  function extractFirstJson(text) {
    const start = text.indexOf('{');
    if (start === -1) return null;
    let depth=0, inStr=false, esc=false;
    for (let i=start;i<text.length;i++) {
      const ch=text[i];
      if(esc){esc=false;continue;}
      if(ch==='\\'){esc=true;continue;}
      if(ch==='"'){inStr=!inStr;continue;}
      if(inStr)continue;
      if(ch==='{')depth++;
      if(ch==='}')depth--;
      if(depth===0)return text.slice(start,i+1);
    }
    return null;
  }
  const jsonStr = extractFirstJson(rawText);
  if (!jsonStr) throw new Error('No JSON válido. Respuesta: '+rawText.substring(0,700));
  parsed = JSON.parse(jsonStr);
}
const missing=['title','excerpt','content'].filter(f=>!parsed[f]);
if(missing.length>0) {
  return [{ json: { error_ia: true, message: `Campos faltantes: ${missing.join(', ')}`, raw: rawText } }];
}
return [{ json: parsed }];

const article = $input.first().json;
let ctx = {};
try {
  ctx = $('Preparar Contexto Editorial').first().json || {};
} catch (e) {}

const rawTags = article.tags || article.Tags || ctx.Tags || [];
const tagsArray = Array.isArray(rawTags)
  ? rawTags.map((tag) => String(tag || '').trim()).filter(Boolean)
  : String(rawTags || '').split(',').map((tag) => tag.trim()).filter(Boolean);

const categorySlug = String(article.category_slug || ctx.category_slug || 'ia')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-+|-+$/g, '') || 'ia';

const excerptSource = String(article.excerpt || article.meta_description || '');
const excerpt = excerptSource.length > 157 ? excerptSource.substring(0, 157) + '...' : excerptSource;
const metaSource = String(article.meta_description || article.excerpt || excerptSource || '');
const meta_description = metaSource.length > 157 ? metaSource.substring(0, 157) + '...' : metaSource;

const featuredImage = String(ctx.imagen_destacada_url || '').trim();
const bodyImage1 = String(ctx.imagen_body1_url || '').trim();
const bodyImage2 = String(ctx.imagen_body2_url || '').trim();
if (!featuredImage || !bodyImage1 || !bodyImage2) {
  throw new Error('Faltan imagenes generadas para publicar el articulo.');
}
if (new Set([featuredImage, bodyImage1, bodyImage2]).size < 3) {
  throw new Error('Las imagenes generadas no son unicas. Deben existir portada, cuerpo 1 y cuerpo 2 distintas.');
}

let content = String(article.content || '').trim();
if (!content) {
  throw new Error('El articulo no devolvio contenido HTML.');
}

const figureRegex = /<figure>[\s\S]*?<img[^>]*>[\s\S]*?<\/figure>/gi;
const figures = content.match(figureRegex) || [];
if (figures.length < 2) {
  throw new Error('El articulo debe incluir exactamente dos imagenes dentro del cuerpo.');
}
const forcedFigures = [bodyImage1, bodyImage2];
let figureIndex = 0;
content = content.replace(figureRegex, (figureHtml) => {
  const targetImage = forcedFigures[figureIndex++];
  if (!targetImage || figureIndex > 2) {
    return figureHtml;
  }
  if (figureHtml.includes('<figcaption>')) {
    return figureHtml.replace(/<img[^>]*>/i, '<img src="' + targetImage + '" alt="Imagen editorial de LOOKITRY para ecommerce de moda" />');
  }
  return '<figure><img src="' + targetImage + '" alt="Imagen editorial de LOOKITRY para ecommerce de moda" /></figure>';
});

const emptyImages = content.match(/<img[^>]+src=["']\s*["'][^>]*>/gi) || [];
if (emptyImages.length > 0) {
  throw new Error('El articulo quedo con imagenes vacias.');
}

const bodyImages = Array.from(content.matchAll(/<img[^>]+src=["']([^"']+)["'][^>]*>/gi)).map((match) => String(match[1] || '').trim());
if (bodyImages.length < 2 || bodyImages[0] !== bodyImage1 || bodyImages[1] !== bodyImage2) {
  throw new Error('El cuerpo del articulo no quedo con las dos imagenes correctas.');
}
if (bodyImages.includes(featuredImage)) {
  throw new Error('La portada no puede repetirse dentro del cuerpo del articulo.');
}

const normalizeSlug = (value) => String(value || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-+|-+$/g, '');
const currentSlug = normalizeSlug(article.title);
const relatedLinks = Array.isArray(ctx.enlacesBlogs)
  ? ctx.enlacesBlogs.filter((link) => {
      const url = String(link?.url || '').trim();
      return url && !url.endsWith('/' + currentSlug);
    }).slice(0, 2)
  : [];

const internalLinks = content.match(/https:\/\/lookitry\.com\/blog\/[^"'\s<]+/gi) || [];
if (internalLinks.length < 2) {
  if (relatedLinks.length < 2) {
    throw new Error('No hay suficientes backlinks internos para publicar el articulo.');
  }

  const backlinksBlock = '<div data-blog-block="impact"><h3>Sigue aprendiendo con LOOKITRY</h3><ul>' + relatedLinks.map((link) => '<li><a href="' + String(link.url).trim() + '">' + String(link.titulo || 'Articulo relacionado de LOOKITRY').trim() + '</a></li>').join('') + '</ul></div>';
  if (content.includes('data-blog-cta="final"')) {
    content = content.replace(/<div data-blog-cta="final"/i, backlinksBlock + '<div data-blog-cta="final"');
  } else {
    content += backlinksBlock;
  }
}

const softCta = '<p class="soft-cta" style="background:#f9f9f9; padding:15px; border-left:4px solid #FF5C3A; font-style:italic;"><strong>Te identificas con este reto?</strong> Descubre como LOOKITRY ayuda a las tiendas de moda a <a href="https://lookitry.com/trial-checkout" style="color:#FF5C3A;">activar una prueba paga y mejorar la conversion con IA</a>.</p>';
if (/<p class="soft-cta"[\s\S]*?<\/p>/i.test(content)) {
  content = content.replace(/<p class="soft-cta"[\s\S]*?<\/p>/i, softCta);
} else {
  content = content.replace(/(<h2[^>]*>)/i, softCta + '$1');
}

const finalCta = '<div data-blog-cta="final" style="text-align: center; padding: 40px; background: #0A0A0A; border-radius: 30px; margin: 50px 0;"><h3 style="color: #FFFFFF; margin-bottom: 20px;">Quieres ver como funcionaria LOOKITRY en tu tienda?</h3><a href="https://lookitry.com/trial-checkout" style="background: #FF5C3A; color: white; padding: 15px 30px; border-radius: 50px; text-decoration: none; font-weight: bold; display: inline-block;">Iniciar prueba de LOOKITRY</a></div>';
if (/<div data-blog-cta="final"[\s\S]*?<\/div>/i.test(content)) {
  content = content.replace(/<div data-blog-cta="final"[\s\S]*?<\/div>/i, finalCta);
} else {
  content += finalCta;
}

const wpBody = {
  title: article.title,
  excerpt,
  content,
  status: 'published',
  category_slug: categorySlug,
  tags: tagsArray,
  featured_image: featuredImage,
  meta_description,
  topic_id: ctx.topic_id || '',
  author_id: 'LOOKITRY Editorial',
};

return [{
  json: {
    wpBody,
    ...ctx,
    tags: tagsArray,
    category_slug: categorySlug,
    title: article.title,
    excerpt,
    content,
    meta_description,
  },
}];

const topicId = $('Preparar Contexto Editorial').first().json?.topic_id || 'desconocido';
const title = $('Preparar Contexto Editorial').first().json?.title || 'desconocido';
const respuesta = $input.first().json;
console.log(`ERROR AL PUBLICAR: topic_id=${topicId}, title=${title}`);
console.log('Respuesta Lookitry:', JSON.stringify(respuesta));
return [{ json: { error: true, topic_id: topicId, title, response: respuesta, timestamp: new Date().toISOString() } }];

const temaActual = $('Loop Temas Pendientes').item.json || {};
const topicId = temaActual.topic_id || 'N/A';
const title = temaActual.title || 'N/A';

console.log(`✓ Artículo publicado en Lookitry y actualizado en Supabase. topic_id=${topicId}, title=${title}`);
return [{ json: { success: true, topic_id: topicId, title, timestamp: new Date().toISOString() } }];
